// 1949—2035 ordinary-life expansion. These are deliberately low-weight,
// one-off textures: they enrich a life without making one policy or fashion
// happen to everybody who happened to be alive in the same year.

const ALL = ["village", "town", "county", "city", "tier2", "tier1"];
const RURAL = { hukou: ["rural"], cityTiers: ["village", "town"] };
const URBAN = { cityTiers: ["county", "city", "tier2", "tier1"] };
const MARKET = { cityTiers: ["town", "county", "city", "tier2", "tier1"] };
const COAST = {
  provinces: ["liaoning", "tianjin", "shandong", "jiangsu", "shanghai", "zhejiang", "fujian", "guangdong", "guangxi", "hainan"],
  cityTiers: ["town", "county", "city", "tier2", "tier1"],
};
const NORTHEAST = { provinces: ["liaoning", "jilin", "heilongjiang"], cityTiers: ["town", "county", "city", "tier2", "tier1"] };
const WEST = { provinces: ["sichuan", "chongqing", "guizhou", "yunnan", "shaanxi", "gansu", "qinghai", "ningxia", "xinjiang", "guangxi"], cityTiers: ALL };

const C = (path, op, value) => ({ path, [op]: value });
const lowWealth = (specific, fallback) => [
  { conditions: { all: [C("resources.wealth", "lte", 35)] }, text: specific },
  { text: fallback },
];
const femaleText = (specific, fallback) => [
  { conditions: { all: [C("birth.gender", "eq", "female")] }, text: specific },
  { text: fallback },
];
const careerText = (field, specific, fallback) => [
  { conditions: { all: [C("career.field", "eq", field)] }, text: specific },
  { text: fallback },
];
const healthText = (specific, fallback) => [
  { conditions: { all: [C("resources.health", "lte", 45)] }, text: specific },
  { text: fallback },
];
const E = ({ id, title, category = "daily", yearRange, ageRange, currentRegions, conditions, text, effects = [], ...rest }) => ({
  id: `exp49_${id}`,
  title,
  category,
  yearRange,
  ageRange,
  currentRegions,
  conditions,
  maxOccurrences: 1,
  baseWeight: 16,
  text,
  effects,
  ...rest,
});

